function isTechDashboardView() {
  return dashboardViewMode === "tech";
}

function applyDashboardViewMode() {
  document.body.classList.toggle("dashboard-tech", isTechDashboardView());
  const toggle = document.querySelector("#viewModeToggle");
  if (toggle) {
    toggle.textContent = isTechDashboardView() ? "经典版" : "科技版";
    toggle.setAttribute("aria-pressed", String(isTechDashboardView()));
    toggle.setAttribute("title", isTechDashboardView() ? "切换回经典页面" : "切换到科技感地图页面");
  }
}

function setDashboardViewMode(mode) {
  dashboardViewMode = mode === "tech" ? "tech" : "classic";
  localStorage.setItem("getinge-dashboard-view-mode-v1", dashboardViewMode);
  applyDashboardViewMode();
  if (dashboardInitialized) {
    renderDashboard();
    setTimeout(() => {
      trendChart?.resize();
      yearTrendChart?.resize();
      mapChart?.resize();
    }, 0);
  }
}

const importedUsersStorageKey = "getinge-dashboard-imported-users-v1";
const authUsersApiEndpoint = "/api/users";
const dashboardDataApiEndpoint = "/api/dashboard-data";
const sessionApiEndpoint = "/api/session";
const sessionPasswordApiEndpoint = "/api/session/password";
const testDashboardKey = "testMagnusIb";
const testPageAssets = {
  magnusIbMainVisual: "assets/test-pages/test-magnus-ib-main-visual-v1.png",
  magnusIbHeatMap: "assets/test-pages/test-magnus-ib-heatmap-v2.png",
  magnusIbBanner: "assets/test-pages/test-magnus-ib-banner-v1.jpg"
};
const isHttpMode = window.location.protocol.startsWith("http");
let importedUsersCache = [];
let authUsersBackendAvailable = false;
let dashboardDataBackendAvailable = false;
let dashboardInitialized = false;
let currentSessionUser = null;

function normalizeCredential(value) {
  return String(value ?? "").trim();
}

function getImportedUsers() {
  return importedUsersCache;
}

function getAuthenticatedUser() {
  return currentSessionUser;
}

function isTestUser(user = getAuthenticatedUser()) {
  return normalizeCredential(user?.username).toLowerCase() === "test";
}

function effectiveDashboardKey(key = currentDashboardKey) {
  return key;
}

function createTestDashboardVariant(sourceDashboard) {
  const clone = cloneDashboardData(sourceDashboard);
  clone.title = "TEST Magnus IB Dashboard";
  clone.rankingTitle = "TEST Magnus IB 用户排名";
  clone.modalTitle = "TEST Magnus IB 项目录入与更新";
  clone.visual = {
    ...clone.visual,
    src: testPageAssets.magnusIbMainVisual,
    alt: "TEST 1180 Magnus operating table system"
  };
  return clone;
}

function syncTestDashboardVariant() {
  if (!dashboards?.magnus1180) return;
  dashboards[testDashboardKey] = createTestDashboardVariant(dashboards.magnus1180);
}

function visibleDashboardOptions() {
  const options = [
    { value: "magnus1180", label: "Magnus Dashboard" },
    { value: "magnus2026Funnel", label: "Magnus 2026 Funnel" },
    { value: "tegris", label: "Tegris Dashboard" },
    { value: "icMic", label: "IC MIC Dashboard" }
  ];

  if (isTestUser()) {
    options.unshift({ value: testDashboardKey, label: "TEST Magnus IB" });
  }

  return options;
}

function renderProductSwitcherOptions() {
  syncTestDashboardVariant();
  const switcher = document.querySelector("#productSwitcher");
  if (!switcher) return;

  const options = visibleDashboardOptions();
  switcher.innerHTML = options.map((option) => (
    `<option value="${option.value}">${option.label}</option>`
  )).join("");

  if (!isTestUser() && currentDashboardKey === testDashboardKey) {
    currentDashboardKey = "magnus1180";
  }

  if (!options.some((option) => option.value === currentDashboardKey)) {
    currentDashboardKey = options[0]?.value || "magnus1180";
  }

  switcher.value = currentDashboardKey;
}

function getLocalImportedUsers() {
  try {
    return JSON.parse(localStorage.getItem(importedUsersStorageKey)) || [];
  } catch (error) {
    return [];
  }
}

function setLocalImportedUsers(users) {
  localStorage.setItem(importedUsersStorageKey, JSON.stringify(users));
}

async function readJson(response) {
  return response.json().catch(() => ({}));
}

async function fetchJson(url, options = {}) {
  if (!isHttpMode) {
    throw new Error("请通过 http://localhost:8080 打开页面，file:// 方式无法连接登录服务。");
  }

  const response = await fetch(url, {
    credentials: "same-origin",
    cache: "no-store",
    ...options
  });
  const payload = await readJson(response);
  if (!response.ok) {
    const error = new Error(payload.error || "请求失败。");
    error.status = response.status;
    throw error;
  }
  return payload;
}

function setUserImportStatus(message) {
  const target = document.querySelector("#userImportStatus");
  if (target) {
    target.textContent = message;
  }
}

async function loadCurrentSession() {
  try {
    const payload = await fetchJson(sessionApiEndpoint);
    currentSessionUser = payload.user || null;
    return currentSessionUser;
  } catch (error) {
    currentSessionUser = null;
    return null;
  }
}

async function loadImportedUsers() {
  const localUsers = getLocalImportedUsers();
  importedUsersCache = localUsers;

  if (!isAdminUser(getAuthenticatedUser())) {
    authUsersBackendAvailable = false;
    return false;
  }

  try {
    const payload = await fetchJson(authUsersApiEndpoint);
    importedUsersCache = Array.isArray(payload.users) ? payload.users : [];
    setLocalImportedUsers(importedUsersCache);
    authUsersBackendAvailable = true;
    return true;
  } catch (error) {
    authUsersBackendAvailable = false;
    importedUsersCache = localUsers;
    return false;
  }
}

async function setImportedUsers(users) {
  try {
    const payload = await fetchJson(authUsersApiEndpoint, {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ users })
    });
    importedUsersCache = Array.isArray(payload.users) ? payload.users : [];
    setLocalImportedUsers(importedUsersCache);
    authUsersBackendAvailable = true;
    return importedUsersCache;
  } catch (error) {
    authUsersBackendAvailable = false;
    return users;
  }
}

function cloneDashboardData(source) {
  return JSON.parse(JSON.stringify(source));
}

async function loadDashboardData() {
  try {
    const payload = await fetchJson(dashboardDataApiEndpoint);
    if (payload.dashboards && typeof payload.dashboards === "object") {
      dashboards = payload.dashboards;
      dashboardDataBackendAvailable = true;
      return true;
    }
  } catch (error) {
    dashboardDataBackendAvailable = false;
  }

  return false;
}

async function saveDashboardData(nextDashboards) {
  dashboards = nextDashboards;

  try {
    const payload = await fetchJson(dashboardDataApiEndpoint, {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({ dashboards })
    });
    if (payload.dashboards && typeof payload.dashboards === "object") {
      dashboards = payload.dashboards;
    }
    dashboardDataBackendAvailable = true;
  } catch (error) {
    dashboardDataBackendAvailable = false;
  }

  return dashboards;
}

function setAuthClasses(isAuthenticated) {
  document.body.classList.toggle("auth-locked", !isAuthenticated);
  document.body.classList.toggle("authenticated", isAuthenticated);
}

function setLoginMessage(message, type = "error") {
  const target = document.querySelector("#loginMessage");
  target.textContent = message;
  target.classList.toggle("success", type === "success");
}

function isAdminUser(user) {
  const text = `${user?.username || ""} ${user?.displayName || ""} ${user?.role || ""} ${user?.position || ""}`.toLowerCase();
  return normalizeCredential(user?.username).toLowerCase() === "maquet"
    || text.includes("系统管理员")
    || text.includes("admin");
}

function renderAdminTools() {
  const tools = document.querySelector("#adminUserTools");
  if (!tools) return;
  tools.hidden = !isAdminUser(getAuthenticatedUser());
}

function setPasswordMessage(message, type = "error") {
  const target = document.querySelector("#passwordMessage");
  target.textContent = message;
  target.classList.toggle("success", type === "success");
}

function setAuthenticatedUser(user) {
  currentSessionUser = {
    username: user.username,
    displayName: user.displayName || user.username,
    role: user.role || user.position || "授权用户"
  };
  setAuthClasses(true);
  renderUserProfile();
  renderAdminTools();
  initializeDashboardApp();
}

async function clearAuthenticatedUser() {
  currentSessionUser = null;
  try {
    await fetchJson(sessionApiEndpoint, { method: "DELETE" });
  } catch (error) {
    // Ignore logout cleanup failures and clear the UI state anyway.
  }
  setAuthClasses(false);
  renderUserProfile();
  renderAdminTools();
  importedUsersCache = [];
  document.querySelector("#loginPassword").value = "";
  setLoginMessage("已退出登录，请重新输入账号密码。");
  setTimeout(() => document.querySelector("#loginUsername").focus(), 0);
}

function renderUserProfile() {
  const user = getAuthenticatedUser();
  const displayNameTarget = document.querySelector("#userDisplayName");
  const positionTarget = document.querySelector("#userPosition");

  if (!displayNameTarget || !positionTarget) {
    return;
  }

  displayNameTarget.textContent = user?.displayName || user?.username || "--";
  positionTarget.textContent = user?.role || "授权用户";
}

function showPasswordModal() {
  document.querySelector("#passwordForm").reset();
  setPasswordMessage("");
  document.querySelector("#passwordModal").hidden = false;
  setTimeout(() => document.querySelector("#newPassword").focus(), 0);
}

function hidePasswordModal() {
  document.querySelector("#passwordModal").hidden = true;
}

async function updateCurrentUserPassword(password) {
  const sessionUser = getAuthenticatedUser();
  if (!sessionUser?.username) {
    throw new Error("请先登录后再修改密码。");
  }

  await fetchJson(sessionPasswordApiEndpoint, {
    method: "PATCH",
    headers: {
      "Content-Type": "application/json"
    },
    body: JSON.stringify({
      password
    })
  });
}

function importedUserFromRow(row) {
  const normalizedRow = Object.fromEntries(
    Object.entries(row).map(([key, value]) => [String(key).trim().toLowerCase(), value])
  );
  const username = normalizeCredential(
    normalizedRow.username
    || normalizedRow.user
    || normalizedRow.account
    || normalizedRow["用户名"]
    || normalizedRow["用户"]
    || normalizedRow["账号"]
  );
  const password = normalizeCredential(
    normalizedRow.password
    || normalizedRow.pass
    || normalizedRow["密码"]
  );

  if (!username || !password) {
    return null;
  }

  return {
    username,
    password,
    displayName: normalizeCredential(normalizedRow.name || normalizedRow.displayname || normalizedRow["名称"] || normalizedRow["姓名"]) || username,
    role: normalizeCredential(normalizedRow.role || normalizedRow.position || normalizedRow["职位"] || normalizedRow["角色"]) || "user"
  };
}

async function mergeImportedUsers(nextUsers) {
  const userMap = new Map();
  getImportedUsers().forEach((user) => userMap.set(user.username.toLowerCase(), user));
  nextUsers.forEach((user) => userMap.set(user.username.toLowerCase(), user));
  const mergedUsers = [...userMap.values()];
  return setImportedUsers(mergedUsers);
}

async function importUsersFromExcel(file) {
  if (!file) {
    return;
  }

  if (!window.XLSX) {
    document.querySelector("#userImportStatus").textContent = "Excel 解析库未加载，请检查 assets/xlsx.full.min.js。";
    return;
  }

  const data = await file.arrayBuffer();
  const workbook = XLSX.read(data, { type: "array" });
  const firstSheetName = workbook.SheetNames[0];
  const rows = XLSX.utils.sheet_to_json(workbook.Sheets[firstSheetName], { defval: "" });
  const importedUsers = rows.map(importedUserFromRow).filter(Boolean);

  if (!importedUsers.length) {
    document.querySelector("#userImportStatus").textContent = "未找到用户数据，请使用 序号/名称/职位/用户名/密码 表头。";
    return;
  }

  const mergedUsers = await mergeImportedUsers(importedUsers);
  const storageLabel = authUsersBackendAvailable ? "后台" : "本机";
  document.querySelector("#userImportStatus").textContent = `已导入 ${importedUsers.length} 位用户，${storageLabel}共 ${mergedUsers.length} 位授权用户。`;
  setLoginMessage("用户导入成功，可以直接登录。", "success");
}

function normalizedSheetRow(row) {
  return Object.fromEntries(
    Object.entries(row).map(([key, value]) => [String(key).trim().toLowerCase(), value])
  );
}

function sheetCell(row, aliases) {
  const normalizedRow = normalizedSheetRow(row);
  for (const alias of aliases) {
    const value = normalizedRow[String(alias).trim().toLowerCase()];
    if (value !== undefined && value !== null && String(value).trim() !== "") {
      return value;
    }
  }
  return "";
}

function normalizeProductKey(value) {
  const key = String(value ?? "").trim();
  const aliases = {
    "1180": "magnus1180",
    "1180 magnus": "magnus1180",
    "1180 magnus or table": "magnus1180",
    "1180页面": "magnus1180",
    "magnus": "magnus1180",
    "magnus1180": "magnus1180",
    "magnus funnel": "magnus2026Funnel",
    "magnus 2026 funnel": "magnus2026Funnel",
    "1180 magnus funnel": "magnus2026Funnel",
    "2026 funnel": "magnus2026Funnel",
    "funnel": "magnus2026Funnel",
    "magnus2026funnel": "magnus2026Funnel",
    "tegris": "tegris",
    "tegris dashboard": "tegris",
    "tegris页面": "tegris",
    "ic": "icMic",
    "ic mic": "icMic",
    "ic-mic": "icMic",
    "ic mic dashboard": "icMic",
    "ic-mic页面": "icMic",
    "icmic": "icMic",
    "icMic": "icMic"
  };
  return aliases[key.toLowerCase()] || key;
}

function normalizeWinRate(value) {
  const match = String(value ?? "").match(/20|40|60|80|100/);
  return match ? match[0] : "";
}

function funnelModelFromRate(value) {
  const rate = normalizeWinRate(value);
  return rate ? `${rate} Funnel` : "";
}

function normalizeLineKey(value) {
  const key = String(value ?? "").trim();
  return key && key.toLowerCase() !== "all" && key !== "全部" ? key.toLowerCase() : "";
}

function normalizeModelKey(value) {
  return String(value ?? "")
    .trim()
    .toLowerCase()
    .replace(/\s+/g, "")
    .replace(/-/g, "");
}

function canonicalProvinceName(value) {
  const raw = String(value ?? "").trim();
  if (!raw) {
    return "";
  }

  return provinceNames.find((province) => province === raw)
    || provinceNames.find((province) => province.replace(/省|市|壮族自治区|回族自治区|维吾尔自治区|自治区/g, "") === raw)
    || provinceNames.find((province) => province.includes(raw) || raw.includes(province.replace(/省|市|壮族自治区|回族自治区|维吾尔自治区|自治区/g, "")))
    || raw;
}

function canonicalCityName(value) {
  const raw = String(value ?? "").trim();
  if (!raw) {
    return "";
  }

  if (cityAliases[raw]) return cityAliases[raw];
  const normalized = raw
    .replace(/^(中国|中华人民共和国)/, "")
    .replace(/(城区|市辖区|新区|自治州|地区|盟|特别行政区)$/g, "")
    .trim();
  if (cityAliases[normalized]) return cityAliases[normalized];
  if (cityCoordinates[normalized]) return normalized;
  if (cityCoordinates[`${normalized}市`]) return `${normalized}市`;

  const cityMatch = raw.match(/([\u4e00-\u9fa5]{2,8}市)/);
  if (cityMatch) {
    const matched = cityAliases[cityMatch[1]] || cityMatch[1];
    if (cityCoordinates[matched]) return matched;
  }

  return cityNames.find((city) => raw.includes(city) || city.includes(raw)) || "";
}

function inferCityName(...values) {
  for (const value of values) {
    const direct = canonicalCityName(value);
    if (direct) {
      return direct;
    }
  }

  const combined = values.map((value) => String(value || "")).join(" ");
  return cityNames.find((city) => combined.includes(city))
    || customerCityRules.find(([pattern]) => combined.includes(pattern))?.[1]
    || Object.entries(cityAliases).find(([alias]) => combined.includes(alias))?.[1]
    || "";
}

function cityCoordinateForRecord(record) {
  const city = inferCityName(record.installCity, record.terminalUser, record.installProvince, record.channelName, record.configDescription);
  if (city && cityCoordinates[city]) {
    return { city, coord: cityCoordinates[city] };
  }

  const province = canonicalProvinceName(record.installProvince);
  return {
    city: province || record.installProvince || "",
    coord: provinceCoordinates[province] || [104.2, 35.8]
  };
}

function numberCell(row, aliases) {
  const value = Number(sheetCell(row, aliases));
  return Number.isFinite(value) ? value : 0;
}

function dateTextCell(row, aliases) {
  const value = sheetCell(row, aliases);
  if (value instanceof Date) {
    return value.toISOString().slice(0, 10);
  }
  return String(value ?? "").trim();
}

function rowsFromSheet(workbook, sheetName) {
  const sheet = workbook.Sheets[sheetName];
  return sheet ? XLSX.utils.sheet_to_json(sheet, { defval: "", cellDates: true }) : [];
}

function excelDateValue(row, aliases) {
  const value = sheetCell(row, aliases);
  if (value instanceof Date) {
    return value;
  }

  const text = String(value ?? "").trim();
  if (!text) {
    return null;
  }

  const normalized = text.replace(/\//g, "-");
  const parsed = new Date(normalized);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
}

function isoDate(date) {
  return date ? date.toISOString().slice(0, 10) : "";
}

function monthKey(date) {
  return date ? isoDate(date).slice(0, 7) : "";
}

function yearKey(date) {
  return date ? isoDate(date).slice(0, 4) : "";
}

function dateSortValue(record) {
  return (record.primaryDate || record.installDate || record.salesDate || new Date(0)).getTime();
}

function recordPrimaryDate(record, dashboard = {}) {
  if (dashboard.dateBasis === "order") {
    return record.salesDate || record.installDate || null;
  }
  return record.installDate || record.salesDate || null;
}

function dashboardRowsFromSheet(workbook, sheetName, productKey) {
  return rowsFromSheet(workbook, sheetName)
    .map((row) => {
      const winRate = normalizeWinRate(sheetCell(row, ["赢率", "Funnel赢率", "Funnel_Win_Rate", "winRate"]));
      const productModel = String(sheetCell(row, ["型号选择", "型号", "productModel", "产品型号"])).trim() || funnelModelFromRate(winRate);
      const installProvince = canonicalProvinceName(sheetCell(row, ["装机省份", "省份", "installProvince"]));
      const terminalUser = String(sheetCell(row, ["终端用户", "用户", "医院", "客户", "hospitalName"])).trim();
      const quantity = numberCell(row, ["数量", "装机量", "quantity", "value"]) || 1;

      if (!productModel || !installProvince || !terminalUser || quantity <= 0) {
        return null;
      }

      return {
        serialNo: String(sheetCell(row, ["装机编号", "Serial_No", "serialNo", "序列号", "SN"])).trim(),
        productKey,
        productModel,
        modelKey: normalizeModelKey(productModel),
        quantity,
        configDescription: String(sheetCell(row, ["配置描述", "配置", "描述", "configuration"])).trim(),
        installProvince,
        installCity: String(sheetCell(row, ["城市", "市", "City", "installCity"])).trim(),
        salesRegion: String(sheetCell(row, ["区域", "Region", "salesRegion"])).trim(),
        terminalUser,
        channelName: String(sheetCell(row, ["销售渠道", "渠道", "channelName"])).trim() || "未填写渠道",
        salesName: String(sheetCell(row, ["销售", "销售姓名", "salesName"])).trim() || "未填写销售",
        salesDate: excelDateValue(row, ["销售时间", "销售日期", "orderDate", "salesDate"]),
        installDate: excelDateValue(row, ["装机时间", "装机日期", "installDate"]),
        warrantyExpireDate: excelDateValue(row, ["保修过期时间", "保修到期", "warrantyExpireDate"]),
        winRate,
        gforceSystemId: String(sheetCell(row, ["Gforce系统编号", "Gforce 系统编号", "Gforce_System_ID", "gforceSystemId"])).trim()
      };
    })
    .filter(Boolean);
}

function dashboardRowsFromUnifiedSheet(workbook) {
  return rowsFromSheet(workbook, "装机数据")
    .map((row) => {
      const productKey = normalizeProductKey(sheetCell(row, ["产品", "产品页面", "product", "productKey"]));
      const winRate = normalizeWinRate(sheetCell(row, ["赢率", "Funnel赢率", "Funnel_Win_Rate", "winRate"]));
      const productModel = String(sheetCell(row, ["型号", "型号选择", "productModel", "产品型号"])).trim() || funnelModelFromRate(winRate);
      const installProvince = canonicalProvinceName(sheetCell(row, ["省份", "装机省份", "installProvince"]));
      const terminalUser = String(sheetCell(row, ["最终客户", "终端用户", "用户", "医院", "客户", "hospitalName"])).trim();
      const quantity = numberCell(row, ["数量", "装机量", "quantity", "value"]) || 1;

      if (!productKey || !productModel || !installProvince || !terminalUser || quantity <= 0) {
        return null;
      }

      return {
        serialNo: String(sheetCell(row, ["装机编号", "Serial_No", "serialNo", "序列号", "SN"])).trim(),
        productKey,
        productModel,
        modelKey: normalizeModelKey(productModel),
        quantity,
        configDescription: String(sheetCell(row, ["配置", "配置描述", "描述", "configuration"])).trim(),
        installProvince,
        installCity: String(sheetCell(row, ["城市", "市", "City", "installCity"])).trim(),
        salesRegion: String(sheetCell(row, ["区域", "Region", "salesRegion"])).trim(),
        terminalUser,
        channelName: String(sheetCell(row, ["销售渠道", "渠道", "channelName"])).trim() || "未填写渠道",
        salesName: String(sheetCell(row, ["销售", "销售姓名", "salesName"])).trim() || "未填写销售",
        salesDate: excelDateValue(row, ["订单时间", "销售时间", "销售日期", "orderDate", "salesDate"]),
        installDate: excelDateValue(row, ["装机时间", "装机日期", "installDate"]),
        warrantyExpireDate: excelDateValue(row, ["保修过期时间", "保修到期", "warrantyExpireDate"]),
        winRate,
        gforceSystemId: String(sheetCell(row, ["Gforce系统编号", "Gforce 系统编号", "Gforce_System_ID", "gforceSystemId"])).trim()
      };
    })
    .filter(Boolean);
}

function sumRecords(records) {
  return records.reduce((sum, record) => sum + record.quantity, 0);
}

function topGroupedRecords(records, keyGetter, provinceGetter) {
  const map = new Map();
  records.forEach((record) => {
    const key = keyGetter(record);
    if (!key) {
      return;
    }
    const item = map.get(key) || { name: key, province: provinceGetter(record), value: 0 };
    item.value += record.quantity;
    map.set(key, item);
  });

  return [...map.values()]
    .sort((a, b) => b.value - a.value)
    .slice(0, 8);
}

function latestRecord(records, dashboard = {}) {
  return [...records]
    .sort((a, b) => dateSortValue({ ...b, primaryDate: recordPrimaryDate(b, dashboard) }) - dateSortValue({ ...a, primaryDate: recordPrimaryDate(a, dashboard) }))[0];
}

function generatedProvinceData(records, dashboard = {}) {
  const map = new Map();
  records.forEach((record) => {
    const primaryDate = recordPrimaryDate(record, dashboard);
    const item = map.get(record.installProvince) || {
      name: record.installProvince,
      value: 0,
      latestSite: record.terminalUser,
      latestDate: isoDate(primaryDate),
      coord: provinceCoordinates[record.installProvince] || [104.2, 35.8],
      latestTime: 0
    };
    item.value += record.quantity;

    const time = dateSortValue({ ...record, primaryDate });
    if (time >= item.latestTime) {
      item.latestSite = record.terminalUser;
      item.latestDate = isoDate(primaryDate);
      item.latestTime = time;
    }
    map.set(record.installProvince, item);
  });

  return [...map.values()]
    .sort((a, b) => b.value - a.value)
    .map(({ latestTime, ...item }) => item);
}

function generatedUpdates(records, dashboard = {}) {
  return [...records]
    .sort((a, b) => dateSortValue({ ...b, primaryDate: recordPrimaryDate(b, dashboard) }) - dateSortValue({ ...a, primaryDate: recordPrimaryDate(a, dashboard) }))
    .slice(0, 6)
    .map((record) => {
      const date = recordPrimaryDate(record, dashboard);
      const dateLabel = date ? isoDate(date).slice(5) : "--";
      const config = record.configDescription ? `（${record.configDescription}）` : "";
      return {
        date: dateLabel,
        status: dashboard.dateBasis === "order" ? "下单" : (record.installDate ? "装机" : "签约"),
        text: `${record.terminalUser} 完成 ${record.productModel}${config} ${record.quantity} 台`
      };
    });
}

function generatedMonthlyTrend(records, dashboard = {}) {
  const datedRecords = records.filter((record) => recordPrimaryDate(record, dashboard));
  const months = dashboard.funnelTrendYear
    ? Array.from({ length: 12 }, (_, index) => `${dashboard.funnelTrendYear}-${String(index + 1).padStart(2, "0")}`)
    : (() => {
      const endDate = recordPrimaryDate(latestRecord(datedRecords, dashboard) || {}, dashboard) || new Date();
      const rollingMonths = [];
      for (let index = 11; index >= 0; index -= 1) {
        const date = new Date(endDate.getFullYear(), endDate.getMonth() - index, 1);
        rollingMonths.push(`${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`);
      }
      return rollingMonths;
    })();

  const totals = new Map(months.map((month) => [month, 0]));
  datedRecords.forEach((record) => {
    const key = monthKey(recordPrimaryDate(record, dashboard));
    if (totals.has(key)) {
      totals.set(key, totals.get(key) + record.quantity);
    }
  });

  return months.map((month) => ({ month, installed: totals.get(month) || 0 }));
}

function generatedYearlyTrend(records, dashboard = {}) {
  if (dashboard.hideYearlyTrend) {
    return [];
  }
  const datedRecords = records.filter((record) => recordPrimaryDate(record, dashboard));
  const endYear = Number(yearKey(recordPrimaryDate(latestRecord(datedRecords, dashboard) || {}, dashboard))) || new Date().getFullYear();
  const years = Array.from({ length: 5 }, (_, index) => String(endYear - 4 + index));
  const totals = new Map(years.map((year) => [year, 0]));
  datedRecords.forEach((record) => {
    const key = yearKey(recordPrimaryDate(record, dashboard));
    if (totals.has(key)) {
      totals.set(key, totals.get(key) + record.quantity);
    }
  });

  return years.map((year) => ({ year, installed: totals.get(year) || 0 }));
}

function generatedQuarterUnits(records, dashboard = {}) {
  const datedRecords = records.filter((record) => recordPrimaryDate(record, dashboard));
  const endDate = recordPrimaryDate(latestRecord(datedRecords, dashboard) || {}, dashboard);
  if (!endDate) {
    return 0;
  }

  const quarter = Math.floor(endDate.getMonth() / 3);
  return datedRecords
    .filter((record) => {
      const date = recordPrimaryDate(record, dashboard);
      return date.getFullYear() === endDate.getFullYear() && Math.floor(date.getMonth() / 3) === quarter;
    })
    .reduce((sum, record) => sum + record.quantity, 0);
}

function funnelLineKey(record) {
  const rate = Number(String(record.winRate || record.productModel || "").match(/20|40|60|80|100/)?.[0] || 0);
  if (!rate) return "";
  return rate < 60 ? "funnelLt60" : "funnelGe60";
}

function productLineKeyForRecord(record) {
  if (record.productKey === "magnus2026Funnel") {
    return funnelLineKey(record);
  }
  return record.modelKey || normalizeModelKey(record.productModel);
}

function buildDashboardDataFromRecords(baseDashboard, records) {
  const dashboard = {
    ...baseDashboard,
    provinceData: generatedProvinceData(records, baseDashboard),
    users: topGroupedRecords(records, (record) => record.terminalUser, (record) => record.installProvince),
    partners: topGroupedRecords(records, (record) => record.channelName, (record) => record.installProvince),
    updates: generatedUpdates(records, baseDashboard),
    monthlyTrend: generatedMonthlyTrend(records, baseDashboard),
    yearlyTrend: generatedYearlyTrend(records, baseDashboard),
    totalUnits: sumRecords(records),
    quarterUnits: generatedQuarterUnits(records, baseDashboard),
    sourceRecords: records.map((record) => ({
      ...record,
      salesDate: isoDate(record.salesDate),
      installDate: isoDate(record.installDate),
      warrantyExpireDate: isoDate(record.warrantyExpireDate)
    }))
  };

  dashboard.productLineData = {};
  (baseDashboard.productLineOptions || [])
    .filter((option) => option.value !== "all")
    .forEach((option) => {
      const optionModelKey = normalizeModelKey(option.label);
      const lineRecords = records.filter((record) => (
        productLineKeyForRecord(record) === option.value
          || record.modelKey === optionModelKey
          || normalizeModelKey(record.productModel) === normalizeModelKey(option.value)
      ));
      dashboard.productLineData[option.value] = buildDashboardDataFromRecords({ ...baseDashboard, productLineOptions: [] }, lineRecords);
    });

  return dashboard;
}

function importDashboardDataWorkbook(workbook) {
  const nextDashboards = cloneDashboardData(dashboards);
  const unifiedRecords = dashboardRowsFromUnifiedSheet(workbook);

  if (unifiedRecords.length) {
    Object.keys(nextDashboards).forEach((productKey) => {
      const records = unifiedRecords.filter((record) => record.productKey === productKey);
      if (records.length) {
        nextDashboards[productKey] = buildDashboardDataFromRecords(nextDashboards[productKey], records);
      }
    });
    return nextDashboards;
  }

  const sheetMap = [
    ["magnus1180", "1180用户列表"],
    ["magnus2026Funnel", "Magnus2026Funnel"],
    ["tegris", "Tegris用户列表"],
    ["icMic", "IC-MIC用户列表"]
  ];

  sheetMap.forEach(([productKey, sheetName]) => {
    const records = dashboardRowsFromSheet(workbook, sheetName, productKey);
    if (records.length && nextDashboards[productKey]) {
      nextDashboards[productKey] = buildDashboardDataFromRecords(nextDashboards[productKey], records);
    }
  });

  return nextDashboards;
}

async function importDashboardDataFromExcel(file) {
  if (!file) {
    return;
  }

  if (!window.XLSX) {
    setLoginMessage("Excel 解析库未加载，请检查 assets/xlsx.full.min.js。");
    return;
  }

  const button = document.querySelector("#dashboardExcelButton");
  button.textContent = "正在导入...";
  const data = await file.arrayBuffer();
  const workbook = XLSX.read(data, { type: "array", cellDates: true });
  const nextDashboards = importDashboardDataWorkbook(workbook);
  await saveDashboardData(nextDashboards);
  renderDashboard();
  button.textContent = dashboardDataBackendAvailable ? "导入完成" : "已导入本页";
  setTimeout(() => {
    button.textContent = "更新数据";
  }, 1800);
}

async function initializeAuth() {
  applyDashboardViewMode();
  document.querySelector("#currentDate").textContent = new Date().toISOString().slice(0, 10);
  document.querySelector("#viewModeToggle")?.addEventListener("click", () => {
    setDashboardViewMode(isTechDashboardView() ? "classic" : "tech");
  });

  if (!isHttpMode) {
    setAuthClasses(false);
    renderUserProfile();
    renderAdminTools();
    setLoginMessage("请先运行 node server.mjs，并通过 http://localhost:8080 打开页面。");
    return;
  }

  document.querySelector("#loginForm").addEventListener("submit", async (event) => {
    event.preventDefault();
    const submitButton = event.submitter;
    submitButton.disabled = true;
    submitButton.textContent = "登录中...";
    try {
      const payload = await fetchJson(sessionApiEndpoint, {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          username: document.querySelector("#loginUsername").value,
          password: document.querySelector("#loginPassword").value
        })
      });
      setLoginMessage("登录成功，正在进入看板。", "success");
      setAuthenticatedUser(payload.user || {});
      await loadDashboardData();
      if (isAdminUser(getAuthenticatedUser())) {
        await loadImportedUsers();
        setUserImportStatus(
          getImportedUsers().length
            ? `已加载 ${getImportedUsers().length} 位后台授权用户。`
            : "当前没有已导入的授权用户。"
        );
      } else {
        setUserImportStatus("仅管理员可导入授权用户 Excel。");
      }
      renderAdminTools();
      renderDashboard();
    } catch (error) {
      setLoginMessage(error.message || "用户名或密码不正确。");
    } finally {
      submitButton.disabled = false;
      submitButton.textContent = "登录";
    }
  });

  document.querySelector("#userExcelInput").addEventListener("change", (event) => {
    importUsersFromExcel(event.target.files[0]).catch(() => {
      document.querySelector("#userImportStatus").textContent = "导入失败，请确认文件格式为 .xlsx、.xls 或 .csv。";
    }).finally(() => {
      event.target.value = "";
    });
  });

  document.querySelector("#dashboardExcelButton").addEventListener("click", () => {
    document.querySelector("#dashboardExcelInput").click();
  });

  document.querySelector("#dashboardExcelInput").addEventListener("change", (event) => {
    importDashboardDataFromExcel(event.target.files[0]).catch(() => {
      const button = document.querySelector("#dashboardExcelButton");
      button.textContent = "导入失败";
      setTimeout(() => {
        button.textContent = "更新数据";
      }, 1800);
    }).finally(() => {
      event.target.value = "";
    });
  });

  document.querySelector("#logoutButton").addEventListener("click", clearAuthenticatedUser);
  document.querySelector("#changePasswordButton").addEventListener("click", showPasswordModal);
  document.querySelector("#closePasswordModal").addEventListener("click", hidePasswordModal);
  document.querySelector("#cancelPasswordChange").addEventListener("click", hidePasswordModal);
  document.querySelector("[data-close-password-modal]").addEventListener("click", hidePasswordModal);
  document.querySelector("#passwordForm").addEventListener("submit", (event) => {
    event.preventDefault();
    const nextPassword = normalizeCredential(document.querySelector("#newPassword").value);
    const confirmPassword = normalizeCredential(document.querySelector("#confirmNewPassword").value);

    if (nextPassword.length < 4) {
      setPasswordMessage("新密码至少需要 4 个字符。");
      return;
    }

    if (nextPassword !== confirmPassword) {
      setPasswordMessage("两次输入的新密码不一致。");
      return;
    }

    const submitButton = event.submitter;
    submitButton.disabled = true;
    submitButton.textContent = "正在保存...";
    updateCurrentUserPassword(nextPassword)
      .then(() => {
        setPasswordMessage("密码已更新到后台。", "success");
        setTimeout(hidePasswordModal, 900);
      })
      .catch((error) => {
        setPasswordMessage(error.message || "密码更新失败。");
      })
      .finally(() => {
        submitButton.disabled = false;
        submitButton.textContent = "保存新密码";
        document.querySelector("#passwordForm").reset();
      });
  });

  const currentUser = await loadCurrentSession();
  if (currentUser) {
    await loadDashboardData();
    if (isAdminUser(currentUser)) {
      await loadImportedUsers();
      setUserImportStatus(
        getImportedUsers().length
          ? `已加载 ${getImportedUsers().length} 位后台授权用户。`
          : "当前没有已导入的授权用户。"
      );
    } else {
      setUserImportStatus("仅管理员可导入授权用户 Excel。");
    }
    setAuthClasses(true);
    renderUserProfile();
    renderAdminTools();
    initializeDashboardApp();
  } else {
    setUserImportStatus("仅管理员可导入授权用户 Excel。");
    setAuthClasses(false);
    renderUserProfile();
    renderAdminTools();
    setTimeout(() => document.querySelector("#loginUsername").focus(), 0);
  }
}

function currentDashboard() {
  if (currentDashboardKey === testDashboardKey) {
    syncTestDashboardVariant();
  }
  return dashboards[currentDashboardKey];
}

function currentProductLine() {
  return currentDashboard().productLineOptions?.find((line) => line.value === currentProductLineKey);
}

function lineAdjustedValue(value, productLine) {
  if (productLine?.ratio) {
    return Math.max(1, Math.round(value * productLine.ratio));
  }

  if (productLine?.value === "s600") {
    return Math.max(1, Math.round(value * 0.62));
  }

  if (productLine?.value === "novito") {
    return Math.max(1, value - Math.max(1, Math.round(value * 0.62)));
  }

  return value;
}

function dashboardLinePrefix(dashboard) {
  return dashboard.title
    .replace(" Dashboard 装机看板", "")
    .replace(" 装机看板", "");
}

function productLineTotalUnitsLabel(dashboard, lineLabel) {
  return (dashboard.lineTotalUnitsLabelTemplate || "台 {line} 设备").replace("{line}", lineLabel);
}

function hasDashboardData(dashboard) {
  return Boolean(
    (Number(dashboard.totalUnits) || 0) > 0 ||
    (dashboard.sourceRecords || []).length ||
    (dashboard.provinceData || []).length ||
    (dashboard.users || []).length ||
    (dashboard.partners || []).length ||
    (dashboard.updates || []).length
  );
}

function currentDashboardData() {
  const dashboard = currentDashboard();
  const productLine = currentProductLine();

  if (!productLine || productLine.value === "all") {
    return dashboard;
  }

  const lineLabel = productLine.label;
  const linePrefix = dashboardLinePrefix(dashboard);
  const lineData = dashboard.productLineData?.[productLine.value];

  if (lineData) {
    return {
      ...dashboard,
      ...lineData,
      title: `${linePrefix} ${lineLabel} Dashboard 装机看板`,
      rankingTitle: `${linePrefix} ${lineLabel} 用户排名`,
      modalTitle: `${linePrefix} ${lineLabel} 项目录入与更新`,
      totalUnitsLabel: productLineTotalUnitsLabel(dashboard, lineLabel)
    };
  }

  return {
    ...dashboard,
    title: `${linePrefix} ${lineLabel} Dashboard 装机看板`,
    rankingTitle: `${linePrefix} ${lineLabel} 用户排名`,
    modalTitle: `${linePrefix} ${lineLabel} 项目录入与更新`,
    totalUnitsLabel: productLineTotalUnitsLabel(dashboard, lineLabel),
    provinceData: dashboard.provinceData.map((item) => ({
      ...item,
      value: lineAdjustedValue(item.value, productLine),
      latestSite: `${item.latestSite} ${lineLabel} 项目`
    })),
    users: dashboard.users.map((item) => ({
      ...item,
      value: lineAdjustedValue(item.value, productLine)
    })),
    partners: dashboard.partners.map((item) => ({
      ...item,
      value: lineAdjustedValue(item.value, productLine)
    })),
    updates: dashboard.updates.map((item) => ({
      ...item,
      text: item.text.replace("IC MIC", lineLabel).replace("IC 产线", `${lineLabel} 产线`).replace("MIC 设备", `${lineLabel} 设备`)
    })),
    monthlyTrend: dashboard.monthlyTrend.map((item) => ({
      ...item,
      installed: lineAdjustedValue(item.installed, productLine)
    })),
    yearlyTrend: dashboard.yearlyTrend.map((item) => ({
      ...item,
      installed: lineAdjustedValue(item.installed, productLine)
    }))
  };
}

function projectStorageKey() {
  return `getinge-${currentDashboardKey}-projects-v1`;
}

