function isRenderableFootprintCustomerName(name) {
  const normalized = String(name || "").trim();
  if (!normalized) return false;
  return !/^(?:n\/a|na|none|null|unknown|暂无|未知)$/i.test(normalized);
}

function footprintRailEntries() {
  if (effectiveDashboardKey() === "magnus2026Funnel") {
    return (currentDashboardData().provinceData || [])
      .map((province, index) => ({
        rank: index + 1,
        name: String(province.name || "")
          .replace(/维吾尔自治区|壮族自治区|回族自治区|特别行政区|自治区|省|市/g, "")
          .trim() || province.name,
        meta: `进行中 ${formatNumber.format(province.value || 0)} 台`
      }));
  }

  const groupedCustomers = customerProvinceGroups()
    .flatMap((group) => group.customers)
    .map((customer, index) => ({
      rank: index + 1,
      name: customer.name,
      meta: `${customer.province || "全国"} · 累计 ${formatNumber.format(customer.value || 0)} 台`
    }));

  if (groupedCustomers.length) {
    return groupedCustomers;
  }

  const dashboard = currentDashboardData();
  return (dashboard.provinceData || []).map((province, index) => ({
    rank: index + 1,
    name: province.latestSite || province.name,
    meta: `${province.name} · 累计 ${formatNumber.format(province.value || 0)} 台`
  }));
}

function renderFootprintRailOverlay() {
  const rail = document.querySelector("#footprintRail");
  if (!rail) return;
  const entries = footprintRailEntries();
  if (!entries.length) {
    rail.innerHTML = "";
    return;
  }

  const doubled = [...entries, ...entries];
  rail.innerHTML = `
    <div class="footprint-rail-track">
      ${doubled.map((entry) => `
        <article class="footprint-rail-item">
          <div class="footprint-rail-rank">${String(entry.rank).padStart(2, "0")}</div>
          <div class="footprint-rail-body">
            <strong>${entry.name}</strong>
            <span>${entry.meta}</span>
          </div>
        </article>
      `).join("")}
    </div>
  `;

  requestAnimationFrame(() => {
    const track = rail.querySelector(".footprint-rail-track");
    if (!track) return;
    const uniqueHeight = track.scrollHeight / 2;
    const pixelsPerSecond = 12;
    const minDuration = 120;
    const maxDuration = 900;
    const computedDuration = uniqueHeight > 0
      ? uniqueHeight / pixelsPerSecond
      : entries.length * 5.5;
    const durationSeconds = Math.max(minDuration, Math.min(maxDuration, computedDuration));
    rail.style.setProperty("--rail-duration", `${durationSeconds.toFixed(1)}s`);
  });
}

function footprintStatsSummary() {
  const dashboard = currentDashboardData();
  const records = dashboard.sourceRecords || [];

  if (effectiveDashboardKey() === "magnus2026Funnel") {
    const coveredProvince = new Set(
      records
        .map((record) => String(record.installProvince || "").trim())
        .filter(Boolean)
    ).size;
    const ge60Funnels = records.reduce((sum, record) => {
      const modelText = String(record.productModel || "").trim();
      const modelValue = Number((modelText.match(/^(\d+)/) || [])[1] || 0);
      return modelValue >= 60
        ? sum + Number(record.quantity || 1)
        : sum;
    }, 0);

    return [
      { label: "Covered Province", value: formatNumber.format(coveredProvince) },
      { label: "In Progress", value: formatNumber.format(ge60Funnels) }
    ];
  }

  const currentYear = new Date().getFullYear();
  const previousYear = currentYear - 1;

  const totalInstalls = records.reduce((sum, record) => sum + Number(record.quantity || 1), 0);
  const provincesCovered = new Set(
    records
      .map((record) => String(record.installProvince || "").trim())
      .filter(Boolean)
  ).size;

  const installsPreviousYear = records.reduce((sum, record) => {
    const dateValue = String(record.installDate || record.salesDate || "").trim();
    return dateValue.startsWith(String(previousYear))
      ? sum + Number(record.quantity || 1)
      : sum;
  }, 0);

  return [
    { label: "Total Installs", value: formatNumber.format(totalInstalls) },
    { label: "Provinces Covered", value: formatNumber.format(provincesCovered) },
    { label: `${previousYear} Installs`, value: formatNumber.format(installsPreviousYear) }
  ];
}

