function customerCloudEntries() {
  const dashboard = currentDashboardData();
  if (effectiveDashboardKey() === "magnus2026Funnel") {
    return [];
  }
  const entries = new Map();
  const provinceLeaders = new Set(
    (dashboard.provinceData || [])
      .map((province) => String(province.latestSite || "").trim())
      .filter(Boolean)
  );
  const importantNames = new Set(
    (dashboard.users || [])
      .filter((user, index) => index < 10 || (user.value || 0) >= 4)
      .map((user) => String(user.name || "").trim())
      .filter(Boolean)
  );
  const addName = (name, value = 0) => {
    const normalized = String(name || "").trim();
    if (!normalized || normalized === "未填写终端用户") return;
    const current = entries.get(normalized) || { name: normalized, value: 0, important: false, regionalPeak: false };
    current.value = Math.max(current.value, value || 0);
    current.important = current.important || importantNames.has(normalized);
    current.regionalPeak = current.regionalPeak || provinceLeaders.has(normalized);
    entries.set(normalized, current);
  };
  (dashboard.sourceRecords || []).forEach((record) => {
    addName(record.terminalUser, Number(record.quantity) || 1);
  });
  (dashboard.users || []).forEach((user) => {
    addName(user.name, user.value || 0);
  });
  (dashboard.provinceData || []).forEach((province) => {
    addName(province.latestSite, 0);
  });
  return [...entries.values()];
}

function renderFootprintCustomerCloud() {
  const cloud = document.querySelector("#footprintCustomerCloud");
  if (!cloud) return;
  const entries = customerCloudEntries();
  cloud.innerHTML = "";
  if (!entries.length) return;

  const cycleSeconds = 480;
  const stepSeconds = cycleSeconds / entries.length;
  entries.forEach((entry, index) => {
    const item = document.createElement("span");
    item.className = `footprint-customer${entry.important ? " is-important" : ""}${entry.regionalPeak ? " is-regional-peak" : ""}`;
    item.textContent = entry.name;
    const hashSeed = Array.from(entry.name).reduce((total, char) => total + char.charCodeAt(0), index * 47);
    const sideBias = index % 4;
    const x = sideBias === 0
      ? 8 + (hashSeed % 26)
      : sideBias === 1
        ? 66 + (hashSeed % 26)
        : 18 + (hashSeed % 64);
    let y = sideBias === 2
      ? 22 + (hashSeed % 13)
      : sideBias === 3
        ? 72 + (hashSeed % 18)
        : 20 + ((hashSeed * 7) % 68);
    if (x < 62 && y < 31) {
      y += 17;
    }
    item.style.setProperty("--x", `${Math.min(94, Math.max(5, x))}%`);
    item.style.setProperty("--y", `${Math.min(92, Math.max(10, y))}%`);
    item.style.setProperty("--delay", `${-(index * stepSeconds)}s`);
    item.style.setProperty("--duration", `${cycleSeconds}s`);
    item.style.setProperty("--scale", `${entry.important || entry.regionalPeak ? 1.08 : 0.82 + (hashSeed % 28) / 100}`);
    item.style.setProperty("--peak-opacity", `${entry.important || entry.regionalPeak ? 0.68 : 0.22 + (hashSeed % 16) / 100}`);
    cloud.appendChild(item);
  });
}

function openFootprintMap(event) {
  event?.stopPropagation();
  const overlay = document.querySelector("#footprintOverlay");
  overlay.hidden = false;
  document.body.classList.add("footprint-open");
  setTimeout(() => {
    footprintChart?.resize();
    renderFootprintMap();
  }, 0);
}

function closeFootprintMap() {
  const overlay = document.querySelector("#footprintOverlay");
  if (overlay.hidden) {
    return;
  }

  overlay.hidden = true;
  document.body.classList.remove("footprint-open");
  window.Footprint3D?.stop?.();
}

function hexToRgb(color) {
  const hex = String(color || "").replace("#", "");
  const normalized = hex.length === 3
    ? hex.split("").map((part) => part + part).join("")
    : hex.padEnd(6, "0").slice(0, 6);
  return [
    parseInt(normalized.slice(0, 2), 16),
    parseInt(normalized.slice(2, 4), 16),
    parseInt(normalized.slice(4, 6), 16)
  ];
}

function mixHex(colorA, colorB, factor) {
  const a = hexToRgb(colorA);
  const b = hexToRgb(colorB);
  const ratio = Math.max(0, Math.min(1, factor));
  return `#${a.map((channel, index) => {
    const mixed = Math.round(channel + (b[index] - channel) * ratio);
    return mixed.toString(16).padStart(2, "0");
  }).join("")}`;
}

function hexToRgba(color, alpha) {
  const [red, green, blue] = hexToRgb(color);
  return `rgba(${red}, ${green}, ${blue}, ${alpha})`;
}

function provincePriority(name) {
  const map = effectiveDashboardKey() === "icMic" ? icProvincePriorityMap : provincePriorityMap;
  return map[name] || "";
}

function isPriorityVisible(priority) {
  return !priority || !hiddenPriorityFilters.has(priority);
}

function provincePriorityColor(name, value, maxValue, tech = false) {
  const priority = provincePriority(name);
  const palette = priorityPalettes[priority];
  if (!palette) {
    return tech ? "rgba(45, 82, 112, 0.38)" : "#f3f0ef";
  }

  if (!isPriorityVisible(priority)) {
    return tech ? "rgba(91, 109, 124, 0.34)" : "#e6e3e2";
  }

  const rawRatio = Math.max(0, value || 0) / Math.max(1, maxValue);
  const ratio = tech ? Math.sqrt(rawRatio) : Math.pow(rawRatio, 0.34);
  const color = ratio < 0.68
    ? mixHex(palette.light, palette.base, ratio / 0.68)
    : mixHex(palette.base, palette.dark, (ratio - 0.68) / 0.32);

  return tech ? hexToRgba(color, 0.86) : color;
}

function mapProvinceRegions(provinceData, tech) {
  const provinceValueMap = new Map((provinceData || []).map((item) => [item.name, item]));
  const maxValue = Math.max(1, ...(provinceData || []).map((item) => item.value || 0));
  const featureNames = (chinaGeoJson?.features || [])
    .map((feature) => feature.properties?.name)
    .filter(Boolean);

  return featureNames.map((name) => {
    const source = provinceValueMap.get(name);
    const priority = provincePriority(name);
    const priorityVisible = isPriorityVisible(priority);
    const value = source?.value || 0;
    return {
      name,
      value,
      priority,
      latestSite: source?.latestSite || "",
      latestDate: source?.latestDate || "",
      itemStyle: {
        areaColor: provincePriorityColor(name, value, maxValue, tech),
        borderColor: priorityVisible
          ? (tech ? "rgba(222, 250, 252, 0.58)" : "rgba(255, 255, 255, 0.92)")
          : (tech ? "rgba(174, 183, 190, 0.28)" : "#d5d0ce"),
        borderWidth: priority ? (tech ? 1.15 : 1) : 0.7,
        shadowBlur: tech && priority && priorityVisible ? 12 : 0,
        shadowColor: tech && priority && priorityVisible ? "rgba(49, 183, 188, 0.18)" : "transparent"
      },
      emphasis: {
        itemStyle: {
          areaColor: priority && priorityVisible ? provincePriorityColor(name, Math.max(value, maxValue * 0.72), maxValue, tech) : undefined,
          borderColor: tech ? "#dffcff" : brandColors.blue,
          borderWidth: 1.4
        },
        label: {
          color: tech ? "#ffffff" : brandColors.blue,
          fontWeight: 700
        }
      }
    };
  });
}

async function renderMap() {
  await ensureChinaMap();
  const provinceData = currentDashboardData().provinceData;
  mapChart = mapChart || echarts.init(document.querySelector("#chinaMap"));
  const compact = window.innerWidth < 900;
  const tech = isTechDashboardView();
  const mapRegions = mapProvinceRegions(provinceData, tech);
  const layoutCenter = [`${mapViewState.centerX}%`, `${mapViewState.centerY}%`];
  mapChart.clear();
  mapChart.resize();

  mapChart.setOption({
    color: [brandColors.ocean, brandColors.sun],
    tooltip: {
      trigger: "item",
      borderWidth: 0,
      backgroundColor: "rgba(16, 32, 61, 0.94)",
      textStyle: { color: "#fff" },
      formatter(params) {
        if (params.seriesType === "scatter" || params.seriesType === "effectScatter") {
          return `
            <strong>${params.name}</strong><br/>
            省份：${params.data.province}<br/>
            最新日期：${params.data.latestDate}<br/>
            省内总装机：${params.value[2]} 台
          `;
        }

        const province = provinceData.find((item) => item.name === params.name);
        const priority = provincePriority(params.name);
        const priorityLine = priority ? `<br/>区域级别：${priority}` : "";
        if (!province) {
          return `${params.name}${priorityLine}<br/>暂无装机记录`;
        }

        return `
          <strong>${params.name}</strong><br/>
          区域级别：${priority || "未分级"}<br/>
          总装机量：${province.value} 台<br/>
          最新场地：${province.latestSite}<br/>
          最新日期：${province.latestDate}
        `;
      }
    },
    geo: {
      map: "china",
      roam: true,
      zoom: mapViewState.zoom,
      layoutCenter,
      layoutSize: tech ? (compact ? "105%" : "96%") : (compact ? "102%" : "92%"),
      tooltip: {
        show: true,
        formatter(params) {
          const province = provinceData.find((item) => item.name === params.name);
          const priority = provincePriority(params.name);
          const priorityLine = priority ? `<br/>区域级别：${priority}` : "";
          if (!province) {
            return `${params.name}${priorityLine}<br/>暂无装机记录`;
          }

          return `
            <strong>${params.name}</strong><br/>
            区域级别：${priority || "未分级"}<br/>
            总装机量：${province.value} 台<br/>
            最新场地：${province.latestSite}<br/>
            最新日期：${province.latestDate}
          `;
        }
      },
      itemStyle: {
        areaColor: tech ? "rgba(45, 82, 112, 0.38)" : "#f3f0ef",
        borderColor: tech ? "rgba(126, 224, 230, 0.56)" : brandColors.white,
        borderWidth: tech ? 1.1 : 1.25,
        shadowBlur: 0,
        shadowColor: "transparent"
      },
      regions: mapRegions,
      emphasis: {
        label: { color: tech ? "#ffffff" : brandColors.blue, fontWeight: 700 },
        itemStyle: {
          areaColor: tech ? "rgba(49, 183, 188, 0.64)" : brandColors.sun,
          borderColor: tech ? "#a7f4f3" : brandColors.blue,
          borderWidth: 1.4
        }
      }
    },
    series: [
      {
        name: "最新装机场地",
        type: tech ? "effectScatter" : "scatter",
        coordinateSystem: "geo",
        symbolSize(value) {
          return tech
            ? (compact ? Math.max(10, Math.min(18, value[2] / 2.3)) : Math.max(12, Math.min(28, value[2] / 1.8)))
            : (compact ? Math.max(8, Math.min(15, value[2] + 2)) : Math.max(9, Math.min(22, value[2] + 5)));
        },
        rippleEffect: tech ? {
          brushType: "stroke",
          scale: 4
        } : undefined,
        itemStyle: {
          color: tech ? "#a7f4f3" : brandColors.sun,
          borderColor: tech ? "rgba(148, 182, 84, 0.92)" : brandColors.white,
          borderWidth: 2,
          shadowBlur: tech ? 22 : 12,
          shadowColor: tech ? "rgba(49, 183, 188, 0.72)" : "rgba(243, 146, 0, 0.46)"
        },
        label: {
          show: tech ? !compact : !compact,
          formatter: "{b}",
          color: tech ? "#ffffff" : brandColors.blue,
          fontSize: tech ? 11 : 10,
          fontWeight: tech ? 800 : 400,
          position: "right",
          backgroundColor: tech ? "rgba(10, 24, 50, 0.54)" : "rgba(255, 255, 255, 0.84)",
          padding: tech ? [4, 6] : [3, 5],
          borderRadius: 4
        },
        labelLayout: {
          hideOverlap: true,
          moveOverlap: "shiftY"
        },
        emphasis: {
          scale: 1.12
        },
        data: latestScatterData()
      }
    ]
  }, true);
}

function resetMainMapView() {
  mapViewState = {
    zoom: 1,
    centerX: 50,
    centerY: isTechDashboardView() ? 54 : 53
  };
}

function stepMainMapView(action) {
  const next = { ...mapViewState };
  if (action === "zoom-in") {
    next.zoom = Math.min(2.4, next.zoom + 0.12);
  } else if (action === "zoom-out") {
    next.zoom = Math.max(0.82, next.zoom - 0.12);
  } else if (action === "left") {
    next.centerX = Math.min(62, next.centerX + 1.8);
  } else if (action === "right") {
    next.centerX = Math.max(38, next.centerX - 1.8);
  } else if (action === "up") {
    next.centerY = Math.min(66, next.centerY + 1.8);
  } else if (action === "down") {
    next.centerY = Math.max(40, next.centerY - 1.8);
  } else if (action === "reset") {
    resetMainMapView();
    renderMap();
    return;
  }

  mapViewState = next;
  renderMap();
}

